diff --git a/spec/arcgis.spec.ts b/spec/arcgis.spec.ts
new file mode 100644
index 0000000..1e527a0
--- /dev/null
+++ b/spec/arcgis.spec.ts
@@ -0,0 +1,39 @@
+import { testXMLHttpRequest } from './mockXMLHttpRequest';
+import { ArcGis } from '../src/geocoders/arcgis';
+
+describe('L.Control.Geocoder.ArcGis', () => {
+  it('geocodes Innsbruck', () => {
+    const geocoder = new ArcGis('');
+    const callback = jest.fn();
+    testXMLHttpRequest(
+      'https://geocode.arcgis.com/arcgis/rest/services/World/GeocodeServer/findAddressCandidates?token=&SingleLine=Innsbruck&outFields=Addr_Type&forStorage=false&maxLocations=10&f=json',
+      {
+        spatialReference: { wkid: 4326, latestWkid: 4326 },
+        candidates: [
+          {
+            address: 'Innsbruck, Innsbruck-Stadt, Tirol',
+            location: { x: 11.391300000000058, y: 47.268000000000029 },
+            score: 100,
+            attributes: { Addr_Type: 'Locality' },
+            extent: {
+              xmin: 11.315300000000057,
+              ymin: 47.192000000000029,
+              xmax: 11.467300000000058,
+              ymax: 47.34400000000003
+            }
+          }
+        ]
+      },
+      () => geocoder.geocode('Innsbruck', callback)
+    );
+
+    const feature = callback.mock.calls[0][0][0];
+    expect(feature.name).toBe('Innsbruck, Innsbruck-Stadt, Tirol');
+    expect(feature.center).toStrictEqual({ lat: 47.26800000000003, lng: 11.391300000000058 });
+    expect(feature.bbox).toStrictEqual({
+      _northEast: { lat: 47.34400000000003, lng: 11.467300000000058 },
+      _southWest: { lat: 47.19200000000003, lng: 11.315300000000057 }
+    });
+    expect(callback.mock.calls).toMatchSnapshot();
+  });
+});

diff --git a/spec/mapbox.spec.ts b/spec/mapbox.spec.ts
new file mode 100644
index 0000000..ecb99fc
--- /dev/null
+++ b/spec/mapbox.spec.ts
@@ -0,0 +1,77 @@
+import { testXMLHttpRequest } from './mockXMLHttpRequest';
+import { Mapbox } from '../src/geocoders/mapbox';
+
+describe('L.Control.Geocoder.Mapbox', () => {
+  it('geocodes Milwaukee Ave', () => {
+    const geocoder = new Mapbox('0123');
+    const callback = jest.fn();
+    testXMLHttpRequest(
+      'https://api.mapbox.com/geocoding/v5/mapbox.places/Milwaukee%20Ave.json?access_token=0123',
+      {
+        type: 'FeatureCollection',
+        query: ['825', 's', 'milwaukee', 'ave', 'deerfield', 'il', '60015'],
+        features: [
+          {
+            id: 'address.4356035406756260',
+            type: 'Feature',
+            place_type: ['address'],
+            relevance: 1,
+            properties: {},
+            text: 'Milwaukee Ave',
+            place_name: '825 Milwaukee Ave, Deerfield, Illinois 60015, United States',
+            matching_text: 'South Milwaukee Avenue',
+            matching_place_name:
+              '825 South Milwaukee Avenue, Deerfield, Illinois 60015, United States',
+            center: [-87.921434, 42.166602],
+            geometry: {
+              type: 'Point',
+              coordinates: [-87.921434, 42.166602],
+              interpolated: true,
+              omitted: true
+            },
+            address: '825',
+            context: [
+              {
+                id: 'neighborhood.287187',
+                text: 'Lake Cook Road'
+              },
+              {
+                id: 'postcode.13903677306297990',
+                text: '60015'
+              },
+              {
+                id: 'place.5958304312090910',
+                wikidata: 'Q287895',
+                text: 'Deerfield'
+              },
+              {
+                id: 'region.3290978600358810',
+                short_code: 'US-IL',
+                wikidata: 'Q1204',
+                text: 'Illinois'
+              },
+              {
+                id: 'country.9053006287256050',
+                short_code: 'us',
+                wikidata: 'Q30',
+                text: 'United States'
+              }
+            ]
+          }
+        ],
+        attribution:
+          'NOTICE: © 2018 Mapbox and its suppliers. All rights reserved. Use of this data is subject to the Mapbox Terms of Service (https://www.mapbox.com/about/maps/). This response and the information it contains may not be retained. POI(s) provided by Foursquare.'
+      },
+      () => geocoder.geocode('Milwaukee Ave', callback)
+    );
+
+    const feature = callback.mock.calls[0][0][0];
+    expect(feature.name).toBe('825 Milwaukee Ave, Deerfield, Illinois 60015, United States');
+    expect(feature.center).toStrictEqual({ lat: 42.166602, lng: -87.921434 });
+    expect(feature.bbox).toStrictEqual({
+      _northEast: { lat: 42.166602, lng: -87.921434 },
+      _southWest: { lat: 42.166602, lng: -87.921434 }
+    });
+    expect(callback.mock.calls).toMatchSnapshot();
+  });
+});

diff --git a/spec/photon.spec.ts b/spec/photon.spec.ts
new file mode 100644
index 0000000..3821b8f
--- /dev/null
+++ b/spec/photon.spec.ts
@@ -0,0 +1,65 @@
+import { testXMLHttpRequest } from './mockXMLHttpRequest';
+import { Photon } from '../src/geocoders/photon';
+import { GeocodingResult } from '../src/geocoders/interfaces';
+
+describe('L.Control.Geocoder.Photon', () => {
+  it('geocodes Innsbruck', () => {
+    const geocoder = new Photon();
+    const callback = jest.fn();
+    testXMLHttpRequest(
+      'https://photon.komoot.io/api/?q=Innsbruck',
+      {
+        features: [
+          {
+            geometry: { coordinates: [11.3927685, 47.2654296], type: 'Point' },
+            type: 'Feature',
+            properties: {
+              osm_id: 8182617,
+              osm_type: 'R',
+              extent: [11.3811871, 47.2808566, 11.4181209, 47.2583715],
+              country: 'Austria',
+              osm_key: 'place',
+              city: 'Innsbruck',
+              countrycode: 'AT',
+              osm_value: 'city',
+              name: 'Innsbruck',
+              state: 'Tyrol',
+              type: 'locality'
+            }
+          },
+          {
+            geometry: { coordinates: [11.3959095, 47.2690806], type: 'Point' },
+            type: 'Feature',
+            properties: {
+              osm_id: 7323902269,
+              country: 'Austria',
+              city: 'Innsbruck',
+              countrycode: 'AT',
+              postcode: '6020',
+              type: 'house',
+              osm_type: 'N',
+              osm_key: 'amenity',
+              housenumber: '1',
+              street: 'Universitätsstraße',
+              district: 'Innenstadt',
+              osm_value: 'music_school',
+              name: 'Mozarteum Innsbruck',
+              state: 'Tyrol'
+            }
+          }
+        ],
+        type: 'FeatureCollection'
+      },
+      () => geocoder.geocode('Innsbruck', callback)
+    );
+
+    const feature: GeocodingResult = callback.mock.calls[0][0][0];
+    expect(feature.name).toBe('Innsbruck, Innsbruck, Tyrol, Austria');
+    expect(feature.center).toStrictEqual({ lat: 47.2654296, lng: 11.3927685 });
+    expect(feature.bbox).toStrictEqual({
+      _northEast: { lat: 47.2808566, lng: 11.4181209 },
+      _southWest: { lat: 47.2583715, lng: 11.3811871 }
+    });
+    expect(callback.mock.calls).toMatchSnapshot();
+  });
+});

diff --git a/spec/here.spec.ts b/spec/here.spec.ts
new file mode 100644
index 0000000..4d703e2
--- /dev/null
+++ b/spec/here.spec.ts
@@ -0,0 +1,87 @@
+import { testXMLHttpRequest } from './mockXMLHttpRequest';
+import { HERE } from '../src/geocoders/here';
+import { GeocodingResult } from '../src/geocoders/interfaces';
+
+describe('L.Control.Geocoder.HERE', () => {
+  it('geocodes Innsbruck', () => {
+    const geocoder = new HERE({ app_id: 'xxx', app_code: 'yyy' });
+    const callback = jest.fn();
+    testXMLHttpRequest(
+      'https://geocoder.api.here.com/6.2/geocode.json?searchtext=Innsbruck&gen=9&app_id=xxx&app_code=yyy&jsonattributes=1',
+      {
+        response: {
+          view: [
+            {
+              result: [
+                {
+                  relevance: 1,
+                  matchLevel: 'city',
+                  matchQuality: {
+                    city: 1
+                  },
+                  location: {
+                    locationId: 'NT_Q9dJCLiAU-LWKKq1nkKnGD',
+                    locationType: 'area',
+                    displayPosition: {
+                      latitude: 47.268,
+                      longitude: 11.3913
+                    },
+                    navigationPosition: [
+                      {
+                        latitude: 47.268,
+                        longitude: 11.3913
+                      }
+                    ],
+                    mapView: {
+                      topLeft: {
+                        latitude: 47.35922,
+                        longitude: 11.30194
+                      },
+                      bottomRight: {
+                        latitude: 47.21082,
+                        longitude: 11.45587
+                      }
+                    },
+                    address: {
+                      label: 'Innsbruck, Tirol, Österreich',
+                      country: 'AUT',
+                      state: 'Tirol',
+                      county: 'Innsbruck-Stadt',
+                      city: 'Innsbruck',
+                      postalCode: '6020',
+                      additionalData: [
+                        {
+                          value: 'Österreich',
+                          key: 'CountryName'
+                        },
+                        {
+                          value: 'Tirol',
+                          key: 'StateName'
+                        },
+                        {
+                          value: 'Innsbruck-Stadt',
+                          key: 'CountyName'
+                        }
+                      ]
+                    }
+                  }
+                }
+              ],
+              viewId: 0
+            }
+          ]
+        }
+      },
+      () => geocoder.geocode('Innsbruck', callback)
+    );
+
+    const feature: GeocodingResult = callback.mock.calls[0][0][0];
+    expect(feature.name).toBe('Innsbruck, Tirol, Österreich');
+    expect(feature.center).toStrictEqual({ lat: 47.268, lng: 11.3913 });
+    expect(feature.bbox).toStrictEqual({
+      _northEast: { lat: 47.35922, lng: 11.45587 },
+      _southWest: { lat: 47.21082, lng: 11.30194 }
+    });
+    expect(callback.mock.calls).toMatchSnapshot();
+  });
+});

